import numpy as np

def compute_rrf_score(rank_sparse, rank_dense, k=60):
    return 1.0 / (k + rank_sparse) + 1.0 / (k + rank_dense)

def run_practice():
    score = compute_rrf_score(1, 1, 60)
    assert np.allclose(score, 2.0 / 61.0)
    print('[PASS] RRF score computations verified.')

if __name__ == '__main__':
    run_practice()
